import{_ as s,c as a,o as l,ag as e}from"./chunks/framework.DPDPlp3K.js";const n="/assets/2024-12-25-10-29-55.BeFsd1hx.png",t="/assets/2024-12-25-15-17-46.CPuKU2_D.png",g=JSON.parse('{"title":"引言","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/Linux/getLinux.md","filePath":"计算机/Linux/getLinux.md","lastUpdated":null}'),h={name:"计算机/Linux/getLinux.md"};function r(o,i,d,p,k,u){return l(),a("div",null,i[0]||(i[0]=[e('<div class="tip custom-block"><p class="custom-block-title">TIP</p><p>目的：拥有一个Linux系统</p></div><h1 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h1><p>安装Linux系统需求一般分为两种场景：</p><ol><li>已经拥有Windows系统，还需要一个Linux环境</li><li>在一台新的机器上安装一个全新的Linux系统</li></ol><p><strong>鉴于Windows系统的普及性和简便性, 绝大多数属于第一种情况, 因此强烈推荐不想折腾的话, 完成 <a href="#安装wsl">安装WSL</a> 即可.</strong></p><h1 id="在windows上安装linux" tabindex="-1">在Windows上安装Linux <a class="header-anchor" href="#在windows上安装linux" aria-label="Permalink to &quot;在Windows上安装Linux&quot;">​</a></h1><p>Windows是使用最广泛的系统，在机器安装了Windows的同时还需要Linux系统，解决方案如下，难度逐渐增加：</p><ol><li>在win中安装适用于 Linux 的 Windows 子系统——Windows Subsystem for Linux (WSL)</li><li>先在win中安装虚拟软件，再安装Linux虚拟机</li><li>在机器上安装双系统</li></ol><p><strong>新手完成第一种方式即可.</strong></p><h2 id="安装wsl" tabindex="-1">安装WSL <a class="header-anchor" href="#安装wsl" aria-label="Permalink to &quot;安装WSL&quot;">​</a></h2><ul><li>适用于 Linux 的 Windows 子系统 (WSL) 是 Windows 的一项功能，与传统虚拟机相比，占用的资源量少。</li><li>必须先启用“适用于 Linux 的 Windows 子系统”可选功能，然后才能在 Windows 上安装 Linux 发行版。</li><li>WSL有两个版本 WSL 1 和 WSL 2 。WSL2拥有完整的Linux内核，性能和兼容性更改好，鉴于现在个人电脑几乎都是win10、win11，选择安装WSL2。</li><li><strong>此小节中的命令均为 Windows PoweShell 命令。</strong></li></ul><h3 id="步骤1" tabindex="-1">步骤1 <a class="header-anchor" href="#步骤1" aria-label="Permalink to &quot;步骤1&quot;">​</a></h3><ul><li>首先根据系统版本选择安装方式: <ul><li>检查Windows系统版本：“Win键 + R” &gt;键入“winver” &gt;选择“确定”</li><li>安装WSL2要求<strong>高于一定版本的Windows10或者任何版本的Windows11</strong><ul><li>对于win10 x64 系统：要求版本 1903 或更高版本，内部版本为 18362.1049 或更高版本。</li><li>对于win10 ARM64 系统：要求版本 2004 或更高版本，内部版本为 19041 或更高版本。 <ul><li>如何确定自己计算机的类型（x64或者ARM64）：win键+R &gt;搜索 cmd 或 PowerShell &gt;打开并输入：<code>systeminfo</code>，在输出中查看“系统类型”。(个人用计算机几乎都是x64)</li></ul></li><li>如果是Windows 10 版本 2004 及更高版本（内部版本 19041 及更高版本）或 Windows 11，可以跳到<a href="#步骤3">步骤3</a>使用命令行安装。</li><li>介于上述版本之间的Windows10(即 1903-2004 之间)需要采用下面的手动安装方式.</li><li>低于1903版本, 需要更新Windows版本</li></ul></li></ul></li></ul><h3 id="步骤2" tabindex="-1">步骤2 <a class="header-anchor" href="#步骤2" aria-label="Permalink to &quot;步骤2&quot;">​</a></h3><ul><li>开启Windows功能：桌面搜索框搜索“功能” &gt;打开“启用或关闭Windows功能” &gt;在最下面找到并勾选“适用于 Linux 的 Windows 子系统”和“虚拟机平台” <img src="'+n+`" alt="img"></li><li><strong>步骤2</strong>——命令行实现(上一步做了这一步跳过)：“开始”菜单 &gt;“PowerShell” &gt;单击右键 &gt;“以管理员身份运行”，然后输入以下命令：</li></ul><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dism.exe</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">online </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">enable-feature</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">featurename:Microsoft</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Windows</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Subsystem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Linux </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">all </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">norestart</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">dism.exe</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">online </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">enable-feature</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">featurename:VirtualMachinePlatform </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">all </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">norestart</span></span></code></pre></div><ul><li><strong>然后重启计算机</strong>，然后执行<a href="#步骤4">步骤4</a>开始手动安装。</li></ul><h3 id="步骤3" tabindex="-1">步骤3 <a class="header-anchor" href="#步骤3" aria-label="Permalink to &quot;步骤3&quot;">​</a></h3><ul><li>一个命令安装运行 WSL 所需的一切内容：win键 &gt;搜索“powershell” &gt;“PowerShell” &gt;单击右键 &gt;“以管理员身份运行” &gt;输入命令: <code>wsl --install</code></li><li>上述命令将默认安装 Linux 的 Ubuntu 发行版. 如果你不了解, 保持默认即可; 若想安装其它发行版，可以使用下面的命令更改版本(这一步与上一步选择一个执行即可)：</li></ul><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#列出可用的 Linux 发行版</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wsl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">list </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">online</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#选择一个版本安装</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wsl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Distribution Name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><ul><li><strong>然后重启计算机</strong>, 再次回到 PowerShell，输入 <code>wsl</code>启动Linux，或者使用“开始”菜单打开该发行版（默认情况下为 Ubuntu）。系统将要求你为 Linux 发行版创建“用户名”和“密码”。 <ul><li>此用户名和密码特定于安装的每个单独的 Linux 分发版，与 Windows 用户名无关。</li><li>请注意，输入密码时，屏幕上不会显示任何内容。 这称为盲人键入。 你不会看到你正在键入的内容，这是完全正常的。</li><li>创建用户名和密码后，该帐户将是分发版的默认用户，并将在启动时自动登录。</li><li>此帐户将被视为 Linux 管理员，能够运行 sudo (Super User Do) 管理命令。</li></ul></li><li>然后执行<a href="#步骤5">步骤5</a></li></ul><h3 id="步骤4" tabindex="-1">步骤4 <a class="header-anchor" href="#步骤4" aria-label="Permalink to &quot;步骤4&quot;">​</a></h3><ul><li>下载 Linux 内核更新包 <ul><li><a href="https://wslstorestorage.blob.core.windows.net/wslblob/wsl_update_x64.msi" target="_blank" rel="noreferrer">适用于 x64 计算机的 WSL2 Linux 内核更新包</a></li><li><a href="https://wslstorestorage.blob.core.windows.net/wslblob/wsl_update_arm64.msi" target="_blank" rel="noreferrer">适用于ARM64 计算机的WSL2 Linux 内核更新包</a></li></ul></li><li>运行上一步中下载的更新包。（双击以运行 - 系统将提示你提供提升的权限，选择“是”以批准此安装。）</li><li>将 WSL 2 设置为默认版本: win键 &gt;搜索“powershell” &gt;“PowerShell” &gt;单击右键 &gt;“以管理员身份运行” &gt;在PowerShell中输入命令 <code>wsl --set-default-version 2</code></li><li>打开微软商店，搜索你偏好的 Linux 分发版(如果你不了解, 选择下面第一个Ubuntu即可)，选择“获取”即可安装。 <ul><li>下面是网页连接，可以跳转到微软商店或者下载 <code>.exe</code>安装程序:</li><li><a href="https://apps.microsoft.com/detail/9pn20msr04dw?rtc=1&amp;hl=zh-CN&amp;gl=CN" target="_blank" rel="noreferrer">Ubuntu 22.04 LTS</a></li><li><a href="https://apps.microsoft.com/detail/9msvkqc78pk6?rtc=1&amp;hl=zh-CN&amp;gl=CN" target="_blank" rel="noreferrer">Debian GNU/Linux</a></li></ul></li><li>完成后可以在“开始”菜单找到刚安装的Linux发行版, 打开它。首次启动新安装的 Linux 分发版时，将打开一个控制台窗口，系统会要求你等待一分钟或两分钟，以便文件解压缩并存储到电脑上。为新的 Linux 分发版创建用户帐户和密码。 <img src="`+t+`" alt="img"></li></ul><h3 id="步骤5" tabindex="-1">步骤5 <a class="header-anchor" href="#步骤5" aria-label="Permalink to &quot;步骤5&quot;">​</a></h3><ul><li>检查是否成功安装WSL2，打开 PowerShell，输入命令 <code>wsl --list --verbose</code>查看安装的WSL版本.</li><li>输出应该如下：</li></ul><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> wsl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">list </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">verbos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  NAME      STATE           VERSION</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Ubuntu    Stopped         </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span></code></pre></div><p><strong>当你看到Linux发行版的名字及版本，祝贺你！ 已成功安装了与 Windows 操作系统完全集成的 Linux ！</strong></p><h3 id="卸载wsl" tabindex="-1">卸载WSL <a class="header-anchor" href="#卸载wsl" aria-label="Permalink to &quot;卸载WSL&quot;">​</a></h3><ul><li>想要删除一个WSL发行版与该发行版相关的所有数据，请运行 <code>wsl --unregister &lt;distroName&gt;</code>，其中 <code>&lt;distroName&gt;</code> 是你的 Linux 发行版的名称，可以用 <code>wsl -l</code> 命令的列表中查看已安装的发行版的名称。此外，可以像卸载任何其他应用商店应用程序一样，在计算机上卸载 Linux 发行版应用</li><li>更多设置及命令在<a href="https://learn.microsoft.com/zh-cn/windows/wsl/" target="_blank" rel="noreferrer">微软WSL文档</a>中可以找到。</li></ul><h2 id="通过虚拟机安装linux" tabindex="-1">通过虚拟机安装Linux <a class="header-anchor" href="#通过虚拟机安装linux" aria-label="Permalink to &quot;通过虚拟机安装Linux&quot;">​</a></h2><p><strong>Windows WSL2 已经完全满足需求, 此方法仅作备选方案</strong>, 大致流程如下:</p><ul><li>VMware是一款知名的虚拟化软件，它通过虚拟化技术，允许用户在同一台物理计算机上运行多个操作系统。2024年5月14日开始，<strong>VMware对个人使用完全免费</strong>。</li><li>首先注册下载软件：<a href="https://access.broadcom.com/default/ui/v1/signin/" target="_blank" rel="noreferrer">Workstation Pro 17.5.2 下载</a> (适用于 Windows 桌面上的虚拟化)</li><li>像Windows其它应用程序一样安装好后, 就可以得到一个虚拟环境</li><li>打开VMware，选择“创建新的虚拟机”。</li><li>选择“典型（推荐）”安装方式，然后选择“稍后安装操作系统”。</li><li>在操作系统类型中选择“Linux”，并根据需要选择具体的Linux发版本（如Ubuntu、CentOS等）</li><li>然后根据题提示设置名称和存储位置, 根据实际需求分配处理器, 内存和磁盘</li><li>在虚拟机设置中，将光驱设置为ISO映像文件路径，指向下载的Linux系统镜像文件 (.iso 镜像文件一般从各种Linux发行版的官网可以下载到)</li><li>启动虚拟机，系统会自动加载ISO镜像中的安装程序。</li><li>然后根据安装向导安装即可, 过程类似Windows系统的激活过程</li><li>安装完成后，重启进入系统即可得到一个运行在虚拟软件中的Linux系统</li><li>如果你觉得不够详细, 相关教程网络上所处可见, 参考教程: <a href="https://blog.csdn.net/2301_76831056/article/details/142769348" target="_blank" rel="noreferrer">VMware虚拟机17.6安装Ubuntu20.04教程-CSDN博客</a></li></ul><h2 id="双系统" tabindex="-1">双系统 <a class="header-anchor" href="#双系统" aria-label="Permalink to &quot;双系统&quot;">​</a></h2><p>如果你需要一个从各个方面来说都完整的Linux系统, 还不想舍弃Windows, 双系统是最好的选择. 除了需要配置一些启动文件以外, 这几乎和单独安装Linux系统没有任何区别.</p><p>既然都选择了拥有一个开源的Linux, 我希望它是自由的, 在众多发行版中选择了自由的 Arch Linux, 它允许用户从安装到配置的每一个细节都进行自定义.</p><p>感谢伟大的开源运动, 让所有人有自由使用各种软件的权利.</p><h3 id="安装自由的arch-linux" tabindex="-1">安装自由的Arch Linux <a class="header-anchor" href="#安装自由的arch-linux" aria-label="Permalink to &quot;安装自由的Arch Linux&quot;">​</a></h3><ul><li>#待更</li></ul><h4 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h4><ul><li>在Arch Linux的官网wiki可以找到详细的安装信息和其他配置信息</li><li>准备一个U盘并, 下载iso镜像, 写入arch live环境</li><li>拥有一定的空余磁盘空间, 可以是D盘中的剩余空间, 也可以用&quot;压缩卷&quot;压缩出来的空间, 也可以是一块新的磁盘</li><li>Arch Linux 安装镜像不支持 UEFI 安全启动（Secure Boot）功能, 需要在BIOS中禁用安全启动(F2)</li><li>启动到live环境(F12), 将会以 root 身份登录进入一个虚拟控制台，默认的 Shell 是 Zsh。</li></ul><h4 id="连接到互联网" tabindex="-1">连接到互联网 <a class="header-anchor" href="#连接到互联网" aria-label="Permalink to &quot;连接到互联网&quot;">​</a></h4><h4 id="磁盘分区和挂载" tabindex="-1">磁盘分区和挂载 <a class="header-anchor" href="#磁盘分区和挂载" aria-label="Permalink to &quot;磁盘分区和挂载&quot;">​</a></h4><h4 id="安装必要的软件" tabindex="-1">安装必要的软件 <a class="header-anchor" href="#安装必要的软件" aria-label="Permalink to &quot;安装必要的软件&quot;">​</a></h4><h4 id="生成fstab文件" tabindex="-1">生成fstab文件 <a class="header-anchor" href="#生成fstab文件" aria-label="Permalink to &quot;生成fstab文件&quot;">​</a></h4><h4 id="新系统的配置" tabindex="-1">新系统的配置 <a class="header-anchor" href="#新系统的配置" aria-label="Permalink to &quot;新系统的配置&quot;">​</a></h4><h4 id="安装引导程序" tabindex="-1">安装引导程序 <a class="header-anchor" href="#安装引导程序" aria-label="Permalink to &quot;安装引导程序&quot;">​</a></h4><h4 id="最后检查" tabindex="-1">最后检查 <a class="header-anchor" href="#最后检查" aria-label="Permalink to &quot;最后检查&quot;">​</a></h4><h1 id="安装独立的linux" tabindex="-1">安装独立的Linux <a class="header-anchor" href="#安装独立的linux" aria-label="Permalink to &quot;安装独立的Linux&quot;">​</a></h1><p>此方法与双系统安装过程类似, 甚至更为简单, 不做更多的记录.</p>`,49)]))}const x=s(h,[["render",r]]);export{g as __pageData,x as default};
